def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(7, 1, -1):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    term2 = np.cos(ratio * b / (a + 2)) * np.sin(ratio / (b + 1) * a)
                    priority += term1 * term2 * np.exp(-(ratio - a)/2)
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.5)) ** 2 + np.cos(ratio * 3) * 4
        elif 5 < ratio <= 8:
            for m in range(1, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 3):
                    val = ((ratio - m) ** 4) * np.sin(ratio * m / (n + 1)) / (n + 0.7)
                    priority += np.tanh(val) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5 + np.sin(ratio * 0.7) * 2.2
        elif 2 < ratio <= 5:
            s = 0
            for p in range(1, 15):
                s += ((ratio - 2) ** p) / (p * 2.1) * np.cos(p * ratio) * np.exp(-p / 10)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 8 + np.tanh(5 * (5 - ratio)) * 3
            if bin_cap < item * 3:
                priority += np.sqrt(item * bin_cap) * 1.7
            else:
                priority -= np.exp(-ratio) * 2.3
        elif 1 < ratio <= 2:
            s = 0
            for q in range(1, 12):
                s += ((2 - ratio) ** q) / (q ** 2 + 0.7) * np.sin(q * ratio * 1.3)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 0.9)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for r in range(1, 6):
                priority += np.sin(r * ratio * i) * ((ratio - 1) ** r) / (r + 0.5) * 0.8
        elif 0.5 <= ratio < 1:
            s = 0
            for s_idx in range(1, 20):
                s += ((1 - ratio) ** s_idx) / (s_idx * 3.5) * np.cos(s_idx * item * 1.4)
            priority = s
            if (i * int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.5)
            for t in range(1, 8):
                priority += ((1 - ratio) ** t) * np.sin(t * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for u in range(1, 15):
                s += ((0.5 - ratio) ** u) / (u * 5) * np.cos(u * ratio * 2.3) * np.exp(-u / 15)
            priority = s + 3 / (bin_cap + 4)
            if int(item * 1.5) % 6 == 0:
                priority *= 3.7
            else:
                priority /= 3.2
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.8
            for v in range(1, 8):
                priority += ((0.5 - ratio) ** v) / (v * 7) * np.cos(item * v * 1.3) * 0.85
        elif 0 < ratio < 0.2:
            s = 0
            for w in range(1, 18):
                s += ((0.2 - ratio) ** w) / (w * 6) * np.sin(w * item * 1.1) * np.exp(-w / 20)
            priority = s + 4 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for x in range(1, 10):
                priority += ((0.2 - ratio) ** x) / (x * 8) * np.cos(item * x * 0.7) * 0.95
        else:
            s = 0
            for y in range(1, 14):
                s += ((0 - ratio) ** y) / (y * 7) * np.sin(y * item * 1.0) * np.exp(-y / 25)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 8 == 0:
                priority *= 3.5
            else:
                priority /= 3.8
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5.5
            for z in range(1, 12):
                priority += ((0 - ratio) ** z) / (z * 9) * np.cos(item * z * 0.6) * 1.1
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx_offset in range(1, 6):
            idx_sum = i + idx_offset
            if idx_sum % 5 == 0:
                priority += np.sin(ratio * idx_sum) * 0.5
            else:
                priority -= np.cos(ratio * idx_sum) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.8 + np.cos(i * ratio * 0.5) * 0.3
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.8 + np.sin(i * ratio * 0.7) * 0.3
        if i % 2 == 0:
            for _ in range(3):
                priority += np.tanh(ratio * (i + 1)) * 0.4
        else:
            for _ in range(2):
                priority -= np.tanh(ratio * (i + 2)) * 0.4
        if (bin_cap + item) % 7 < 3:
            priority += np.log1p(bin_cap + item) * 2.3
        else:
            priority -= np.exp(-(bin_cap + item) / 5) * 2.1
        priorities[i] = priority
    return priorities
